INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4a75df8f-44f8-4b9e-870a-27a61e7b3d24',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon PoS Block Architecture — Bor Sprints, Heimdall Checkpoints, and Transaction Finality$escape$,
  $escape$Polygon PoS runs two layers under the hood: Bor (the EVM execution layer, a modified Geth fork) and Heimdall (a Tendermint-based validator coordination layer). Bor produces blocks every ~2 seconds, grouped into 'sprints' (16 blocks) within larger 'spans' (~6400 blocks, ~3.5 hrs). A single producer handles each sprint — selected deterministically from the active validator set staked on Ethereum L1.

Accounts are EVM-identical: EOAs and contract accounts share the same 20-byte address space, nonce semantics, and ECDSA signing. Transactions are standard EIP-1559 (type 2) with one Polygon-specific twist — gas is paid in POL (formerly MATIC), not ETH.

Finality is two-tiered: Bor blocks give probabilistic finality in seconds, but cryptographic finality only arrives when Heimdall validators submit a checkpoint merkle root to the Ethereum mainnet `RootChainManager` contract, roughly every 256 Bor blocks (~512s). For bridge operations or cross-chain proofs, always wait for checkpoint inclusion — not just block confirmation. Use the Polygon checkpointing API or watch the `NewHeaderBlock` event on Ethereum to detect it.$escape$,
  $escape$import { ethers } from 'ethers';

// Polygon PoS mainnet RPC
const provider = new ethers.JsonRpcProvider('https://polygon-rpc.com');

async function inspectBlock() {
  const block = await provider.getBlock('latest');
  console.log('Block number:', block.number);
  console.log('Block time (s):', block.timestamp - (await provider.getBlock(block.number - 1)).timestamp);
  console.log('Gas used / limit:', `${block.gasUsed} / ${block.gasLimit}`);
  console.log('Base fee (gwei):', ethers.formatUnits(block.baseFeePerGas ?? 0n, 'gwei'));
  console.log('Tx count:', block.transactions.length);
}

inspectBlock();$escape$,
