INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0c2a62cd-22e3-4979-968b-5d0ba59297dd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon Architecture Deep Dive — PoS, AggLayer, zkEVM, and Bridging$escape$,
  $escape$Polygon PoS runs on a dual-client setup: Bor produces blocks while Heimdall checkpoints them to Ethereum via Tendermint BFT roughly every 30 minutes. That checkpoint window is why native PoS withdrawals carry a ~3-hour exit delay — your burn tx on Polygon must be included in a Heimdall checkpoint before the Ethereum-side exit is provable.

AggLayer rewires this model for CDK chains. Instead of each chain independently posting ZK proofs to L1, AggLayer batches them into a single pessimistic proof — one that guarantees no chain can claim funds it doesn't control, even under a malicious sequencer. This enables atomic cross-chain settlement between any AggLayer-connected chain without 7-day optimistic windows or trusted third-party bridges.

Polygon zkEVM is a Type 2 equivalent EVM rollup that routes through AggLayer. Bridging between zkEVM and a CDK appchain settles via aggregated proof, not message passing. For PoS transfers use `@maticnetwork/maticjs` with the POSClient. For zkEVM use the native bridge contract at `0x2a3DD3EB832aF982ec71669E178424b10Dca2EDe` on Ethereum — or the REST bridge API at `bridge-api.zkevm-rpc.com` for deposit/claim state queries.$escape$,
  $escape$import { POSClient, use } from "@maticnetwork/maticjs";
import { Web3ClientPlugin } from "@maticnetwork/maticjs-web3";

use(Web3ClientPlugin);

const client = new POSClient();
await client.init({
  network: "mainnet",
  version: "v1",
  parent: { provider: ethProvider, defaultConfig: { from: wallet } },
  child:  { provider: polygonProvider, defaultConfig: { from: wallet } },
});

// MATIC ERC-20 on Ethereum (root=true targets parent chain)
const erc20 = client.erc20("0x7D1AfA7B718fb893dB30A3aBc0Cfc608AaCfeBB0", true);
const tx = await erc20.deposit("1000000000000000000", wallet); // 1 MATIC
console.log("Deposit hash:", await tx.getTransactionHash());
// Claimable on Polygon PoS after next Heimdall checkpoint (~30 min)$escape$,
  $escape$typescript$escape$,
