INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e07897b9-c071-44b0-8563-48e086c9e12c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon zkEVM — Why You Skip the 7-Day Optimistic Rollup Withdrawal Wait$escape$,
  $escape$Optimistic rollups like Arbitrum One and Optimism Mainnet assume transactions are valid, then expose a 7-day challenge window so fraud proofs can be submitted before L1 withdrawals finalize. During that window, funds are locked — exiting early costs a liquidity provider fee of 0.1–0.5%. Polygon zkEVM inverts this entirely: every sequenced batch is proven by a ZK validity proof and verified on Ethereum L1 via `verifyBatchesTrustedAggregator()` on the `PolygonRollupManager` contract. There is no optimistic assumption, no challenge period. Once the aggregator submits the proof — typically 30–60 minutes after your transaction is sequenced — your withdrawal is mathematically finalized on L1. The Polygon zkEVM Bridge API (`bridge-api.zkevm-rpc.com`) provides the Merkle proof data needed to call `claimAsset()` or `claimMessage()` on the L1 bridge contract at `0x2a3DD3EB832aF982ec71669E178424b10Dca2EDe`. Claiming is permissionless and immediate once the proof is on-chain. Polygon CDK chains connected via AggLayer inherit this same ZK-finality model — any CDK-built chain sidesteps optimistic delays by design.$escape$,
  $escape$import { ethers } from "ethers";
import axios from "axios";

const BRIDGE_API = "https://bridge-api.zkevm-rpc.com";
const L1_BRIDGE = "0x2a3DD3EB832aF982ec71669E178424b10Dca2EDe";
const ABI = ["function claimAsset(bytes32[32],bytes32[32],uint256,bytes32,bytes32,uint32,address,uint32,address,uint256,bytes) external"];

// Proof available ~30-60 min after sequencing — no 7-day challenge window
async function claimZkEvmWithdrawal(depositCount: number, signer: ethers.Signer) {
  const { data } = await axios.get(
    `${BRIDGE_API}/merkle-proof?deposit_cnt=${depositCount}&net_id=1`
  );
  const { proof } = data;
  const bridge = new ethers.Contract(L1_BRIDGE, ABI, signer);
  const tx = await bridge.claimAsset(
    proof.merkle_proof, proof.rollup_merkle_proof, proof.global_index,
    proof.main_exit_root, proof.rollup_exit_root,
    proof.orig_net, proof.orig_addr, proof.dest_net, proof.dest_addr,
    proof.amount, proof.metadata
  );
  console.log("Withdrawal claimed, no fraud window needed:", tx.hash);
}$escape$,
  $escape$typescript$escape$,
