INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '519d5ff3-3265-4a2d-9f4b-ee36e5f652d5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon Bridges — Lock/Mint, Canonical vs Third-Party, and What Can Go Wrong$escape$,
  $escape$Polygon has two canonical bridges: the PoS Bridge and the LxLy Bridge (Polygon zkEVM / CDK chains). Both use lock/mint: assets lock inside an L1 predicate contract (`ERC20Predicate` at `0x40ec5B33f54e0E8A33A975908C5BA1c14e5BbbDf`), and a mapped child token mints on-chain via `RootChainManager.depositFor()`. Withdrawals on PoS require a checkpoint inclusion (~3 hours), then a separate `exit()` call on mainnet. zkEVM withdrawals require an on-chain verified ZK proof before funds release.

Token mapping is a prerequisite — unmapped tokens sent via the PoS bridge are permanently stuck. Always verify mapping at mapper.polygon.technology before bridging novel ERC-20s.

Third-party bridges (Hop, Across, Stargate) bypass checkpoint delays using liquidity pools with optimistic or ZK verification. Faster, but the trust surface expands: smart contracts, off-chain relayers, and price oracles all become attack vectors. The $625M Ronin and $320M Wormhole exploits both targeted bridge validator/guardian logic.

For security-critical flows — protocol treasuries, DAO contracts — use the canonical PoS or LxLy bridge. Reserve third-party bridges for latency-sensitive UX paths, and only after confirming audits, a live bug bounty, and a TVL-commensurate insurance fund.$escape$,
  $escape$import { ethers } from "ethers";

const ROOT_CHAIN_MANAGER = "0xA0c68C638235ee32657e8f720a23ceC1bFc77C77";
const ERC20_PREDICATE    = "0x40ec5B33f54e0E8A33A975908C5BA1c14e5BbbDf";

const tokenAbi  = ["function approve(address spender, uint256 amount) external returns (bool)"];
const bridgeAbi = ["function depositFor(address user, address rootToken, bytes calldata depositData) external"];

const token  = new ethers.Contract(TOKEN_ADDRESS, tokenAbi, l1Signer);
const bridge = new ethers.Contract(ROOT_CHAIN_MANAGER, bridgeAbi, l1Signer);

// Step 1: approve the predicate to pull tokens
await token.approve(ERC20_PREDICATE, amount);

// Step 2: lock on L1 — child token mints on Polygon PoS within ~5–8 min
const depositData = ethers.AbiCoder.defaultAbiCoder().encode(["uint256"], [amount]);
await bridge.depositFor(recipientAddress, TOKEN_ADDRESS, depositData);$escape$,
  $escape$typescript$escape$,
