INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0f028013-4c4e-4eb0-9832-878e8b5f33a9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon EVM Compatibility — Reuse Your Entire Ethereum Toolchain$escape$,
  $escape$Polygon PoS (chainId: 137) is EVM-compatible: it executes the same EVM bytecode as Ethereum mainnet. Polygon zkEVM (chainId: 1101) goes further — it's a Type-2 zkEVM, meaning near-full EVM equivalence at the opcode level, including support for PUSH0 and SELFDESTRUCT semantics. The practical upshot: any contract compiled with solc targeting Shanghai or earlier deploys identically on both chains with zero modifications.

Tooling reuse is total. Hardhat and Foundry work by swapping the RPC URL. ethers.js and viem need only a chain config change. The ABI, bytecode, and deployment scripts are identical. Even OPCODE gas costs differ slightly from mainnet — Polygon PoS charges 30 gwei base fee vs. Ethereum's variable EIP-1559 market — so gas estimation via eth_estimateGas still applies but results will differ numerically.

For Foundry users, forge script with --rpc-url https://polygon-rpc.com and --broadcast deploys without touching a single line of Solidity. The same forge test suite runs against a Polygon fork via --fork-url, letting you test against live Polygon state locally.$escape$,
  $escape$// viem: configure Polygon PoS and zkEVM chains, then read a contract
import { createPublicClient, http, defineChain } from 'viem'
import { polygon, polygonZkEvm } from 'viem/chains'

// Polygon PoS — chainId 137
const posClient = createPublicClient({
  chain: polygon,
  transport: http('https://polygon-rpc.com'),
})

// Polygon zkEVM — chainId 1101
const zkClient = createPublicClient({
  chain: polygonZkEvm,
  transport: http('https://zkevm-rpc.com'),
})

// Same ABI, same address if deployed to both — EVM bytecode is identical
const balance = await posClient.readContract({
  address: '0xYourContract',
  abi: yourAbi,
  functionName: 'balanceOf',
  args: ['0xYourWallet'],
})$escape$,
