INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '10e655fc-c12a-44a8-af7a-3cca74256d7f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon MEV — Sandwich Attacks Inside Bor Sprints and Private Transaction Defense$escape$,
  $escape$On Polygon PoS, MEV extraction is shaped by Bor's sprint model: one validator produces 16 consecutive ~400ms blocks before rotating. During its sprint, that Bor node controls full transaction ordering — a wider reorg window than Ethereum's single-slot model. Sandwich bots subscribe to the public mempool via `eth_subscribe("pendingTransactions")` on a Polygon RPC, front-run a target DEX swap with a buy, let the victim's tx execute (shifting the AMM price), then back-run with a sell — all within one sprint. Near-zero MATIC gas fees make this profitable on trades as small as $20, a threshold impossible on Ethereum mainnet. PBS is nascent on Polygon: no canonical mev-boost integration exists, but Flashbots Protect supports chainId 137, routing transactions to a private relay that never touches the public mempool. Without a private RPC, your best defense is tight slippage (≤0.5% on Uniswap V3 pools) and a short deadline. On-chain, a sandwich leaves a clear fingerprint: two transactions from the same EOA bracketing yours in the same block with mirrored swap directions on the same pair.$escape$,
  $escape$import { ethers } from "ethers";

// Flashbots Protect on Polygon — transaction never enters public mempool
const provider = new ethers.JsonRpcProvider(
  "https://rpc.flashbots.net?hint=hash",
  { chainId: 137, name: "matic" }
);
const signer = new ethers.Wallet(process.env.PK!, provider);

const deadline = Math.floor(Date.now() / 1000) + 30; // 30s: too short to re-order profitably

const tx = await uniswapV3Router.exactInputSingle({
  tokenIn:  "0x2791Bca1f2de4661ED88A30C99A7a9449Aa84174", // USDC.e on Polygon
  tokenOut: "0x0d500B1d8E8eF31E21C99d1Db9A6444d3ADf1270", // WMATIC
  fee: 500,
  recipient: signer.address,
  deadline,
  amountIn: ethers.parseUnits("100", 6),
  amountOutMinimum: amountOutMin, // computed off-chain at ≤0.5% slippage
  sqrtPriceLimitX96: 0n,
});$escape$,
