INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c4bc3c4f-aa16-4e24-b7cc-7e6eea9c0de0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon Transaction Lifecycle — Mempool, Bor Sprints, and Checkpoint Finality$escape$,
  $escape$When you submit a tx to Polygon PoS, it lands in Bor's mempool — a standard EVM txpool where validators select by gas price. Bor produces blocks every ~2s in fixed sprints (default 16 blocks), with a single validator assigned per sprint. During sprint handoffs, short reorgs of 1–2 blocks are possible — never treat 1-confirmation as final for anything of value.

Soft finality arrives around 128 Bor blocks (~4 min): statistically safe for most dApp flows. True checkpoint finality requires Heimdall to aggregate a span of Bor block hashes and post a checkpoint to the RootChain contract on Ethereum mainnet — roughly every 256 Bor blocks (~8–10 min), but this can lag under L1 congestion.

For bridge withdrawals, finality is explicitly gate-kept: the Polygon SDK's `isCheckPointed(txHash)` returns false until the Heimdall checkpoint lands on L1. For reorg-sensitive operations, track `confirmations = latestBlock - receipt.blockNumber` and enforce a 256-block threshold. Anything below 128 blocks should be treated as provisional, especially for cross-chain or settlement logic.$escape$,
  $escape$import { createPublicClient, http } from "viem";
import { polygon } from "viem/chains";

const client = createPublicClient({ chain: polygon, transport: http() });

async function getTxFinality(txHash: `0x${string}`) {
  const receipt = await client.getTransactionReceipt({ hash: txHash });
  if (!receipt) return { status: "pending" };

  const latestBlock = await client.getBlockNumber();
  const confirmations = latestBlock - receipt.blockNumber;

  // ~256 Bor blocks ≈ one Heimdall checkpoint anchored on Ethereum L1
  if (confirmations >= 256n) return { status: "checkpoint-safe", confirmations };
  if (confirmations >= 128n) return { status: "soft-final", confirmations };
  return { status: "confirming", confirmations };
}$escape$,
  $escape$typescript$escape$,
