INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '77575d29-c6c6-48be-8f03-5638c3d36dee',
  '00000000-0000-0000-0000-000000000001',
  $escape$Polygon Account Abstraction — Gasless Transactions with ERC-4337 Paymasters$escape$,
  $escape$ERC-4337 on Polygon PoS (chain ID 137) replaces EOAs with smart contract wallets that submit `UserOperation` structs to a shared `EntryPoint` at `0x5FF137D4b0FDCD49DcA30c7CF57E578a026d2789`. The bundler batches ops and pays gas in POL on-chain, while a Paymaster can reimburse or fully sponsor those fees.

Biconomy's Paymaster is the most production-battle-tested option on Polygon — it lets you whitelist specific contract calls and sponsor POL gas for your users, removing the onboarding friction of "get MATIC first." Under the hood, the Paymaster signs a `paymasterAndData` field in the UserOperation, which the EntryPoint validates before execution.

With Biconomy's v3 SDK, you create a `SmartAccount` wrapping any EOA signer, point it at Polygon's bundler RPC (`137` network ID), attach a sponsored Paymaster API key, and call `sendTransaction` — the SDK handles nonce management, calldata encoding, gas estimation via `eth_estimateUserOperationGas`, and op submission to the bundler mempool. The user signs once; POL fees are invisible to them.$escape$,
  $escape$import { createSmartAccountClient } from "@biconomy/account";
import { createWalletClient, http } from "viem";
import { polygon } from "viem/chains";

const smartAccount = await createSmartAccountClient({
  signer: walletClient,           // EOA signer (e.g. MetaMask)
  bundlerUrl: `https://bundler.biconomy.io/api/v2/137/${process.env.BUNDLER_KEY}`,
  biconomyPaymasterApiKey: process.env.PAYMASTER_KEY,
  rpcUrl: "https://polygon-rpc.com",
});

const { wait } = await smartAccount.sendTransaction({
  to: "0xYourContract",
  data: encodedCalldata,
  value: 0n,
});

const { transactionHash } = await wait();
console.log("Gasless tx on Polygon:", transactionHash);$escape$,
  $escape$typescript$escape$,
